/**
 * @summary Get price chart data for a cryptocurrency
 */
export const getGetPriceChartUrl = (params: GetPriceChartParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/market/chart?${stringifiedParams}`
    : `/api/market/chart`;
};

export const getPriceChart = async (
  params: GetPriceChartParams,
  options?: RequestInit,
): Promise<PriceChart> => {
  return customFetch<PriceChart>(getGetPriceChartUrl(params), {
    ...options,
    method: "GET",
  });
};

